/**
 * Module dependencies.
 */

var url = require('url');
var parse = url.parse;
var Url = url.Url;

/**
 * Module exports.
 */

module.exports = parseurl;
module.exports.original = originalurl;

/**
 * Parse the `req` url with memoization.
 *
 * @param {ServerRequest} req
 * @return {Object}
 * @api public
 */

function parseurl(req) {
  var url = req.url;

  if (url === undefined) {
    // URL is undefined
    return undefined;
  }

  var parsed = req._parsedUrl;

  if (parsed && parsed._raw === url) {
    return parsed;
  }

  // Parse the URL
  parsed = fastparse(url);
  parsed._raw = url;

  return (req._parsedUrl = parsed);
}

/**
 * Parse the `req` original url with memoization.
 *
 * @param {ServerRequest} req
 * @return {Object}
 * @api public
 */

function originalurl(req) {
  var url = req.originalUrl;

  if (typeof url !== 'string') {
    // URL is undefined or not a string
    return undefined;
  }

  var parsed = req._parsedOriginalUrl;

  if (parsed && parsed._raw === url) {
    return parsed;
  }

  // Parse the URL
  parsed = fastparse(url);
  parsed._raw = url;

  return (req._parsedOriginalUrl = parsed);
}

/**
 * Parse the URL with fast-path short-cut.
 *
 * @param {string} url
 * @return {Object}
 * @api private
 */

function fastparse(url) {
  if (typeof url !== 'string' || url.charCodeAt(0) !== 0x2f /* / */) {
    return parse(url);
  }

  // Fast path for simple URLs like "/" or "/evening"
  var pathname = url;
  var query = null;
  var search = null;

  // Handle query string
  var questionIdx = url.indexOf('?');
  if (questionIdx !== -1) {
    pathname = url.substring(0, questionIdx);
    search = url.substring(questionIdx);
    query = search.substring(1);
  }

  var parsed = new Url();
  parsed.path = url;
  parsed.href = url;
  parsed.pathname = pathname;
  parsed.query = query;
  parsed.search = search;

  return parsed;
}